request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?gateway ?gwName ?choreo WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "f404135647444aedabe98bb54c000517" ;
         bbo:name ?modelName .
  ?model tai:belongsTo ?org .
  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?defs .
  ?gateway a bboExt:EventBasedGateway ;
           tai:belongsTo ?choreo .
  OPTIONAL { ?gateway bbo:name ?gwName . }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?gateway ?gwName WHERE {
  { ?model a bboExt:Model ;
           tai:normalizedId "f404135647444aedabe98bb54c000517" . }
  UNION
  { ?model a bboExt:Model ;
           tai:originalId "f404135647444aedabe98bb54c000517" . }

  ?model bbo:name ?modelName .
  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ; tai:belongsTo ?defs .
  ?gateway a bboExt:EventBasedGateway ; tai:belongsTo ?choreo .
  OPTIONAL { ?gateway bbo:name ?gwName . }
}
LIMIT 25
